import React, { useState } from "react";

/* ------------------------------------------------------------------ */
/* Helpers                                                             */
/* ------------------------------------------------------------------ */

function uid() {
  return Math.random().toString(36).slice(2, 8);
}

function makeDefaultCategory(key) {
  return {
    key,
    minCapacity: "",
    maxCapacity: "",
    subsidyType: key === "domestic" ? "slab" : "fixed",
    fixedAmount: "",
    percentage: "",
    slabs: [{ id: uid(), from: "", to: "", rate: "" }],
  };
}

/* ------------------------------------------------------------------ */
/* Styles (converted from the original <style> block)                  */
/* ------------------------------------------------------------------ */

const styles = `
.subsidy-wrapper{
  --brand-start:#4c6ef5;
  --brand-end:#7048e8;
  --pink:#e64980;
  --purple:#7c3aed;
  --card-bg:#ffffff;
  --page-bg:#f4f6fb;
  max-width:1100px;
  margin:32px auto;
  font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",Roboto,Helvetica,Arial,sans-serif;
}
.subsidy-card{
  background:var(--card-bg);
  border-radius:16px;
  box-shadow:0 10px 30px rgba(30,40,90,0.08);
  overflow:hidden;
  border:1px solid #eef0f5;
}
.subsidy-topbar{
  height:6px;
  width:100%;
  background:linear-gradient(90deg,var(--brand-start),var(--brand-end));
}
.subsidy-body{
  padding:28px 32px 32px;
}
.subsidy-header{
  display:flex;
  align-items:center;
  gap:14px;
  margin-bottom:24px;
}
.subsidy-icon{
  width:46px;
  height:46px;
  border-radius:12px;
  background:linear-gradient(135deg,var(--brand-start),var(--brand-end));
  display:flex;
  align-items:center;
  justify-content:center;
  color:#fff;
  font-size:20px;
  flex-shrink:0;
}
.subsidy-header h5{
  margin:0;
  font-weight:700;
  color:#20232a;
}
.subsidy-header small{
  color:#8a8f98;
  font-size:0.82rem;
}
.section-label{
  font-size:0.72rem;
  font-weight:700;
  letter-spacing:0.06em;
  color:#8a8f98;
  margin-bottom:10px;
  display:block;
}
.system-type-row{
  display:flex;
  gap:16px;
  margin-bottom:24px;
  flex-wrap:wrap;
}
.system-type-option{
  flex:1 1 260px;
  border:1.5px solid #e4e7ee;
  border-radius:12px;
  padding:16px 18px;
  cursor:pointer;
  display:flex;
  align-items:center;
  gap:12px;
  transition:all .15s ease;
  background:#fafbfd;
}
.system-type-option:hover{
  border-color:#c9cdf0;
}
.system-type-option.active{
  border-color:var(--brand-end);
  background:#f5f4ff;
  box-shadow:0 0 0 3px rgba(112,72,232,0.08);
}
.radio-dot{
  width:18px;
  height:18px;
  border-radius:50%;
  border:2px solid #c7cad4;
  flex-shrink:0;
  display:flex;
  align-items:center;
  justify-content:center;
}
.system-type-option.active .radio-dot{
  border-color:var(--brand-end);
}
.radio-dot .inner-dot{
  width:9px;
  height:9px;
  border-radius:50%;
  background:var(--brand-end);
  display:none;
}
.system-type-option.active .radio-dot .inner-dot{
  display:block;
}
.system-type-option .opt-title{
  font-weight:600;
  font-size:0.95rem;
  color:#22242c;
  margin-bottom:2px;
}
.system-type-option .opt-sub{
  font-size:0.78rem;
  color:#9296a1;
}
.copy-btn-row{
  display:flex;
  gap:12px;
  margin-bottom:20px;
  flex-wrap:wrap;
}
.btn-copy{
  background:#fff;
  border:1.5px solid #e4e7ee;
  color:#4b4f5a;
  font-size:0.82rem;
  font-weight:600;
  border-radius:8px;
  padding:8px 14px;
}
.btn-copy:hover{
  border-color:var(--brand-end);
  color:var(--brand-end);
}
.btn-copy i{
  margin-right:6px;
}
.panel{
  border:1.5px dashed;
  border-radius:14px;
  padding:18px 18px 20px;
  height:100%;
}
.panel-domestic{
  border-color:var(--pink);
}
.panel-commercial{
  border-color:var(--purple);
}
.panel-title{
  display:flex;
  align-items:center;
  gap:8px;
  font-weight:700;
  font-size:0.95rem;
  margin-bottom:16px;
}
.dot-pink,.dot-purple{
  width:9px;height:9px;border-radius:50%;
  display:inline-block;
}
.dot-pink{background:var(--pink);}
.dot-purple{background:var(--purple);}
.form-label-sm{
  font-size:0.72rem;
  font-weight:700;
  letter-spacing:0.04em;
  color:#8a8f98;
  margin-bottom:6px;
  display:block;
}
.form-control-custom{
  border-radius:8px;
  border:1.5px solid #e4e7ee;
  font-size:0.88rem;
  padding:8px 12px;
  height:auto;
  width:100%;
  background:#fff;
  color:#22242c;
}
.form-control-custom:focus{
  outline:none;
  border-color:var(--brand-end);
  box-shadow:0 0 0 3px rgba(112,72,232,0.1);
}
.slab-row{
  display:flex;
  gap:6px;
  align-items:center;
  margin-bottom:10px;
}
.slab-row input{
  min-width:0;
}
.slab-remove{
  background:#fff5f5;
  color:#e0455f;
  border:1.5px solid #ffe1e6;
  border-radius:8px;
  width:34px;
  height:34px;
  flex-shrink:0;
  display:flex;
  align-items:center;
  justify-content:center;
}
.slab-remove:hover{
  background:#ffe1e6;
}
.slab-remove:disabled{
  opacity:0.5;
  cursor:not-allowed;
}
.btn-add-slab{
  background:#fff;
  border:1.5px dashed #c7cad4;
  color:#6a6f7a;
  border-radius:8px;
  font-size:0.82rem;
  font-weight:600;
  padding:8px 12px;
  width:100%;
}
.btn-add-slab:hover{
  border-color:var(--brand-end);
  color:var(--brand-end);
}
.right-grid{
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:20px 24px;
}
@media (max-width: 767px){
  .right-grid{ grid-template-columns:1fr; }
  .subsidy-body{ padding:20px; }
}
.field-group{
  margin-bottom:4px;
}
select.form-control-custom{
  -webkit-appearance:none;
  -moz-appearance:none;
  appearance:none;
  background-image:url("data:image/svg+xml;charset=UTF-8,%3Csvg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'%3E%3Cpath fill='%238a8f98' d='M7 10l5 5 5-5z'/%3E%3C/svg%3E");
  background-repeat:no-repeat;
  background-position:right 10px center;
  background-size:18px;
}
.subsidy-panels-row{
  display:flex;
  gap:24px;
  flex-wrap:wrap;
}
.subsidy-panels-row > div{
  flex:1 1 260px;
}
.subsidy-unit-row{
  display:flex;
  gap:24px;
  flex-wrap:wrap;
}
.subsidy-unit-row > .unit-field{
  flex:0 0 220px;
}
.subsidy-unit-row > .unit-common{
  flex:1 1 400px;
}
.btn-save{
  background:linear-gradient(90deg,var(--brand-start),var(--brand-end));
  border:none;
  border-radius:8px;
  font-weight:600;
  color:#fff;
  padding:10px 24px;
  font-size:0.9rem;
}
.btn-save:hover{
  opacity:0.92;
}
.save-row{
  text-align:right;
  margin-top:24px;
}
`;

/* ------------------------------------------------------------------ */
/* Sub-components                                                       */
/* ------------------------------------------------------------------ */

function SlabRow({ slab, onChange, onRemove, disableRemove }) {
  return (
    <div className="slab-row">
      <input
        type="text"
        className="form-control-custom"
        placeholder="From"
        value={slab.from}
        onChange={(e) => onChange({ ...slab, from: e.target.value })}
      />
      <input
        type="text"
        className="form-control-custom"
        placeholder="To kW"
        value={slab.to}
        onChange={(e) => onChange({ ...slab, to: e.target.value })}
      />
      <input
        type="text"
        className="form-control-custom"
        placeholder="₹ per unit"
        value={slab.rate}
        onChange={(e) => onChange({ ...slab, rate: e.target.value })}
      />
      <button
        type="button"
        className="slab-remove"
        onClick={onRemove}
        disabled={disableRemove}
        title="Remove slab"
      >
        🗑
      </button>
    </div>
  );
}

function CategoryPanel({ label, panelClass, dotClass, category, onUpdate }) {
  const updateField = (field, value) => onUpdate({ ...category, [field]: value });

  const updateSlab = (id, newSlab) => {
    const slabs = category.slabs.map((s) => (s.id === id ? newSlab : s));
    onUpdate({ ...category, slabs });
  };

  const addSlab = () => {
    const slabs = [...category.slabs, { id: uid(), from: "", to: "", rate: "" }];
    onUpdate({ ...category, slabs });
  };

  const removeSlab = (id) => {
    const slabs = category.slabs.filter((s) => s.id !== id);
    onUpdate({ ...category, slabs });
  };

  return (
    <div className={`panel ${panelClass}`}>
      <div className="panel-title">
        <span className={dotClass}></span>
        {label}
      </div>

      <div className="right-grid" style={{ marginBottom: "12px" }}>
        <div>
          <span className="form-label-sm">MIN CAPACITY</span>
          <input
            type="text"
            className="form-control-custom"
            placeholder="e.g. 1"
            value={category.minCapacity}
            onChange={(e) => updateField("minCapacity", e.target.value)}
          />
        </div>
        <div>
          <span className="form-label-sm">MAX CAPACITY</span>
          <input
            type="text"
            className="form-control-custom"
            placeholder="e.g. 500"
            value={category.maxCapacity}
            onChange={(e) => updateField("maxCapacity", e.target.value)}
          />
        </div>
      </div>

      <div style={{ marginBottom: "12px" }}>
        <span className="form-label-sm">SUBSIDY TYPE</span>
        <select
          className="form-control-custom"
          value={category.subsidyType}
          onChange={(e) => updateField("subsidyType", e.target.value)}
        >
          <option value="slab">Slab / Unit based</option>
          <option value="fixed">Fixed</option>
          <option value="percentage">Percentage</option>
        </select>
      </div>

      {category.subsidyType === "slab" && (
        <div>
          <span className="form-label-sm">SLABS</span>
          {category.slabs.map((slab) => (
            <SlabRow
              key={slab.id}
              slab={slab}
              onChange={(newSlab) => updateSlab(slab.id, newSlab)}
              onRemove={() => removeSlab(slab.id)}
              disableRemove={category.slabs.length === 1}
            />
          ))}
          <button type="button" className="btn-add-slab" onClick={addSlab}>
            + Add slab
          </button>
        </div>
      )}

      {category.subsidyType === "fixed" && (
        <div>
          <span className="form-label-sm">FIXED AMOUNT (₹)</span>
          <input
            type="text"
            className="form-control-custom"
            placeholder="e.g. 78000"
            value={category.fixedAmount}
            onChange={(e) => updateField("fixedAmount", e.target.value)}
          />
        </div>
      )}

      {category.subsidyType === "percentage" && (
        <div>
          <span className="form-label-sm">PERCENTAGE (%)</span>
          <input
            type="text"
            className="form-control-custom"
            placeholder="e.g. 40"
            value={category.percentage || ""}
            onChange={(e) => updateField("percentage", e.target.value)}
          />
        </div>
      )}
    </div>
  );
}

function CommonFields({ common, onChange }) {
  const update = (field, value) => onChange({ ...common, [field]: value });

  return (
    <div className="right-grid">
      <div className="field-group">
        <span className="form-label-sm">MAX SUBSIDY CAP (₹)</span>
        <input
          type="text"
          className="form-control-custom"
          placeholder="78000"
          value={common.maxSubsidyCap}
          onChange={(e) => update("maxSubsidyCap", e.target.value)}
        />
      </div>
      <div className="field-group">
        <span className="form-label-sm">ELIGIBILITY DEPENDENCY</span>
        <select
          className="form-control-custom"
          value={common.eligibilityDependency}
          onChange={(e) => update("eligibilityDependency", e.target.value)}
        >
          <option value="pass">Inspection Status: Passed</option>
          <option value="pending">Inspection Status: Pending</option>
          <option value="none">No dependency</option>
        </select>
      </div>

      <div className="field-group">
        <span className="form-label-sm">DISBURSEMENT MODE</span>
        <select
          className="form-control-custom"
          value={common.disbursementMode}
          onChange={(e) => update("disbursementMode", e.target.value)}
        >
          <option value="dbt">DBT (Direct Benefit Transfer)</option>
          <option value="adjustment">Bill Adjustment</option>
          <option value="cheque">Cheque</option>
        </select>
      </div>
      <div className="field-group">
        <span className="form-label-sm">INCOME THRESHOLD (₹)</span>
        <input
          type="text"
          className="form-control-custom"
          placeholder="e.g. < 5 lac"
          value={common.incomeThreshold}
          onChange={(e) => update("incomeThreshold", e.target.value)}
        />
      </div>

      <div className="field-group">
        <span className="form-label-sm">MIN USAGE THRESHOLD</span>
        <input
          type="text"
          className="form-control-custom"
          placeholder="e.g. 100 units/month"
          value={common.minUsageThreshold}
          onChange={(e) => update("minUsageThreshold", e.target.value)}
        />
      </div>
      <div className="field-group">
        <span className="form-label-sm">AMOUNT THRESHOLD (₹)</span>
        <input
          type="text"
          className="form-control-custom"
          placeholder="e.g. 50000"
          value={common.amountThreshold}
          onChange={(e) => update("amountThreshold", e.target.value)}
        />
      </div>
    </div>
  );
}

